INSERT INTO fs_note_templates (id, code, category, label, default_body, sort_order) VALUES
  (UNHEX('FB017A010000000000000000000000A1'), 'AP_INVENTORY',         'accounting_policy',    '棚卸資産の評価方法',             '棚卸資産の評価は、主として総平均法による原価法（貸借対照表価額は収益性の低下による簿価切下げの方法により算定）によっております。', 10),
  (UNHEX('FB017A010000000000000000000000A2'), 'AP_DEPRECIATION',      'accounting_policy',    '有形固定資産の減価償却方法',     '有形固定資産の減価償却は、主として定率法を採用しております。ただし、建物（建物附属設備を除く）については定額法を採用しております。', 20),
  (UNHEX('FB017A010000000000000000000000A3'), 'AP_INTANGIBLE',        'accounting_policy',    '無形固定資産の減価償却方法',     '無形固定資産の減価償却は、定額法を採用しております。自社利用ソフトウェアについては、利用可能期間（5年）に基づく定額法によっております。', 30),
  (UNHEX('FB017A010000000000000000000000A4'), 'AP_ALLOWANCE_DOUBT',   'accounting_policy',    '貸倒引当金の計上基準',           '債権の貸倒れによる損失に備えるため、一般債権については貸倒実績率により、貸倒懸念債権等特定の債権については個別に回収可能性を検討し、回収不能見込額を計上しております。', 40),
  (UNHEX('FB017A010000000000000000000000A5'), 'AP_ALLOWANCE_BONUS',   'accounting_policy',    '賞与引当金の計上基準',           '従業員に対する賞与の支給に備えるため、支給見込額のうち、当事業年度に負担すべき額を計上しております。', 50),
  (UNHEX('FB017A010000000000000000000000A6'), 'AP_RETIREMENT',        'accounting_policy',    '退職給付に係る会計処理',         '退職給付に係る負債及び退職給付費用の計算に、退職給付に係る期末自己都合要支給額を退職給付債務とする方法を用いた簡便法を適用しております。', 60),
  (UNHEX('FB017A010000000000000000000000A7'), 'AP_CONSUMPTION_TAX',   'accounting_policy',    '消費税等の会計処理',             '消費税及び地方消費税の会計処理は、税抜方式によっております。', 70),
  (UNHEX('FB017A010000000000000000000000A8'), 'AP_REVENUE',           'accounting_policy',    '収益及び費用の計上基準',         '収益は、顧客との契約に基づき、履行義務が充足された時点で認識しております。商品の販売については、商品の引渡時点で収益を認識しております。', 80),
  (UNHEX('FB017A010000000000000000000000B1'), 'BS_PLEDGED_ASSETS',    'balance_sheet_notes',  '担保に供している資産',           '当事業年度末において、担保に供している資産は次のとおりであります。（内訳は省略）', 10),
  (UNHEX('FB017A010000000000000000000000B2'), 'BS_ACCUMULATED_DEP',   'balance_sheet_notes',  '有形固定資産の減価償却累計額',   '有形固定資産の減価償却累計額は、       円であります。', 20),
  (UNHEX('FB017A010000000000000000000000B3'), 'BS_RELATED_RECV',      'balance_sheet_notes',  '関係会社に対する金銭債権・債務', '関係会社に対する主な金銭債権及び金銭債務は次のとおりであります。（内訳は省略）', 30),
  (UNHEX('FB017A010000000000000000000000C1'), 'PL_RELATED_TX',        'pl_notes',             '関係会社との取引高',             '関係会社との営業取引及び営業取引以外の取引高は次のとおりであります。（内訳は省略）', 10),
  (UNHEX('FB017A010000000000000000000000C2'), 'PL_RESEARCH_DEV',      'pl_notes',             '研究開発費の総額',               '一般管理費及び当期製造費用に含まれる研究開発費の総額は       円であります。', 20),
  (UNHEX('FB017A010000000000000000000000D1'), 'SS_DIVIDEND',          'ss_notes',             '配当に関する事項',               '当事業年度中の配当金支払額及び基準日が当事業年度に属する配当のうち、配当の効力発生日が翌事業年度となるものは次のとおりであります。', 10),
  (UNHEX('FB017A010000000000000000000000E1'), 'RP_TRANSACTIONS',      'related_party',        '関連当事者との取引',             '関連当事者との取引については、一般的な取引条件と同様に決定しております。', 10),
  (UNHEX('FB017A010000000000000000000000F1'), 'CL_GUARANTEES',        'contingent_liability', '債務保証',                       '関係会社等の金融機関借入金に対して、債務保証を行っております。', 10);
